import React from 'react'
import {Routes, Route} from 'react-router-dom'

import Home from './routes/Home'
import MyCookbook from './routes/MyCookbook'

function App() {
  return (
    <div>
      <Routes>
        <Route path='/' element = {<Home />} />
        <Route path='/myCookbook' element={<MyCookbook />} />
      </Routes>
    </div>
  );
}

export default App;
